package com.grit.liferecorder.ui.routines
import androidx.lifecycle.*; import com.grit.liferecorder.core.date.TimeUtils; import com.grit.liferecorder.data.local.entity.RoutineEntity; import com.grit.liferecorder.data.repository.RoutineRepository; import kotlinx.coroutines.flow.*; import kotlinx.coroutines.launch
data class RoutinesUiState(val routines:List<RoutineEntity> = emptyList())
class RoutinesViewModel(private val repository:RoutineRepository):ViewModel(){ val state=repository.observeRoutines().map{RoutinesUiState(it)}.stateIn(viewModelScope,SharingStarted.WhileSubscribed(5000),RoutinesUiState()); fun add(name:String,days:String){ if(name.isNotBlank() && days.isNotBlank()) viewModelScope.launch{ repository.save(RoutineEntity(name=name,scheduledDays=days,createdAt=TimeUtils.now(),updatedAt=TimeUtils.now()), listOf("Start","Complete")) } }; fun complete(r:RoutineEntity)=viewModelScope.launch{repository.completeToday(r)}; fun skip(r:RoutineEntity)=viewModelScope.launch{repository.skipToday(r)} }
